// Description: Active Discovery script for KubeVirt VMI instances.
// Description: Queries Thanos for running VMs and outputs LogicMonitor discovery format.
// v4

import groovy.json.JsonSlurper

// Embedded ThanosClient class
class ThanosClient {
    private String host
    private String token
    private int port
    private boolean ssl
    private String baseUrl
    private boolean debug

    ThanosClient(Map hostProps) {
        this.host = hostProps.get("kubevirt.thanos.host")
        this.token = hostProps.get("kubevirt.thanos.token")
        this.port = (hostProps.get("kubevirt.thanos.port") ?: "443") as int
        this.ssl = (hostProps.get("kubevirt.thanos.ssl") ?: "true").toLowerCase() == "true"
        this.debug = (hostProps.get("kubevirt.thanos.debug") ?: "false").toLowerCase() == "true"

        if (!this.host) throw new IllegalArgumentException("kubevirt.thanos.host is required")
        if (!this.token) throw new IllegalArgumentException("kubevirt.thanos.token is required")

        def protocol = ssl ? "https" : "http"
        def portSuffix = ((ssl && port == 443) || (!ssl && port == 80)) ? "" : ":${port}"
        this.baseUrl = "${protocol}://${host}${portSuffix}"
    }

    def query(String promql) {
        def encodedQuery = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = "${baseUrl}/api/v1/query?query=${encodedQuery}"
        if (debug) println "DEBUG: ${url}"

        try {
            def response = executeHttpGet(url)
            def json = new JsonSlurper().parseText(response)
            if (json.status != "success") {
                System.err.println "ERROR: ${json.error ?: 'Unknown error'}"
                return null
            }
            return json
        } catch (Exception e) {
            System.err.println "ERROR: ${e.message}"
            return null
        }
    }

    List queryWithLabels(String promql) {
        def json = query(promql)
        if (!json?.data?.result) return []
        return json.data.result.collect { r -> [r.metric ?: [:], r.value ? r.value[1] : null] }
    }

    private String executeHttpGet(String url) {
        try {
            def httpClass = Class.forName("com.santaba.agent.groovyapi.http.HTTP")
            def http = httpClass.newInstance()
            http.open(url)
            http.setHeader("Authorization", "Bearer ${token}")
            def response = http.get()
            http.close()
            return response
        } catch (ClassNotFoundException e) {
            return executeStandardHttpGet(url)
        }
    }

    private String executeStandardHttpGet(String url) {
        def conn = new URL(url).openConnection() as HttpURLConnection
        conn.setRequestMethod("GET")
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(60000)
        if (ssl) {
            try {
                def sc = javax.net.ssl.SSLContext.getInstance("TLS")
                sc.init(null, [new javax.net.ssl.X509TrustManager() {
                    void checkClientTrusted(java.security.cert.X509Certificate[] c, String a) {}
                    void checkServerTrusted(java.security.cert.X509Certificate[] c, String a) {}
                    java.security.cert.X509Certificate[] getAcceptedIssuers() { null }
                }] as javax.net.ssl.TrustManager[], new java.security.SecureRandom())
                conn.setSSLSocketFactory(sc.getSocketFactory())
                conn.setHostnameVerifier({ h, s -> true })
            } catch (Exception e) {}
        }
        if (conn.getResponseCode() != 200) throw new RuntimeException("HTTP ${conn.getResponseCode()}")
        return conn.getInputStream().text
    }
}

// Discovery Logic
try {
    def client = new ThanosClient(hostProps)
    def results = client.queryWithLabels('kubevirt_vmi_info{phase="running"}')

    if (!results) {
        System.err.println "INFO: No running VMIs found"
        return 0
    }

    results.each { labels, value ->
        def ns = labels.get("namespace")
        def name = labels.get("name")
        if (!ns || !name) return

        def node = labels.get("node") ?: "unknown"
        def phase = labels.get("phase") ?: "running"
        def instType = labels.get("instance_type") ?: ""
        def guestOs = labels.get("guest_os_name") ?: ""
        def pref = labels.get("preference") ?: ""

        def wildvalue = "${ns}/${name}"
        def wildalias = name
        def desc = "VM ${name} in namespace ${ns}" + (guestOs ? " (${guestOs})" : "")

        def props = [
            "auto.kubevirt.namespace=${ns}",
            "auto.kubevirt.vmi_name=${name}",
            "auto.kubevirt.node=${node}",
            "auto.kubevirt.phase=${phase}"
        ]
        if (instType) props << "auto.kubevirt.instance_type=${instType}"
        if (guestOs) props << "auto.kubevirt.guest_os=${guestOs}"
        if (pref) props << "auto.kubevirt.preference=${pref}"

        println "${wildvalue}##${wildalias}##${desc}####${props.join('&')}"
    }
    return 0
} catch (Exception e) {
    System.err.println "ERROR: ${e.message}"
    return 1
}

